import { Song } from "./Song";

// Songs receives isFav and onFav from SearchPage and passes them to each Song
export const Songs = ({ fn, allsongs, isFav, onFav }) => {
  return (
    <div className="SongListDisplay">
      {allsongs.map((currentSong) => (
        <Song
          key={currentSong.trackId} // ✅ stable unique key, not index
          fn={fn}
          song={currentSong}
          isFav={isFav} // ✅ passed through
          onFav={onFav} // ✅ passed through
        />
      ))}
    </div>
  );
};
